module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output reg [DATA_WIDTH:0] result,
    output reg o_en
); 
    reg [63:0] adda_reg;
    reg [63:0] addb_reg;
    reg [63:0] sum_stage1;
    reg [63:0] sum_stage2;
    reg [63:0] sum_stage3;
    reg [63:0] sum_stage4;

    reg en_stage1;
    reg en_stage2;
    reg en_stage3;
    reg en_stage4;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'd0;
            addb_reg <= 64'd0;
            sum_stage1 <= 64'd0;
            sum_stage2 <= 64'd0;
            sum_stage3 <= 64'd0;
            sum_stage4 <= 64'd0;

            en_stage1 <= 1'b0;
            en_stage2 <= 1'b0;
            en_stage3 <= 1'b0;
            en_stage4 <= 1'b0;

            o_en <= 1'b0;
        end else begin
            if (i_en) begin
                adda_reg <= adda;
                addb_reg <= addb;

                en_stage1 <= 1'b1;
            end

            if (en_stage1) begin
                sum_stage1 <= adda_reg + addb_reg;

                en_stage2 <= 1'b1;
            end

            if (en_stage2) begin
                sum_stage2 <= sum_stage1;

                en_stage3 <= 1'b1;
            end

            if (en_stage3) begin
                sum_stage3 <= sum_stage2;

                en_stage4 <= 1'b1;
            end

            if (en_stage4) begin
                sum_stage4 <= sum_stage3;

                o_en <= 1'b1;
            end
        end
    end

    assign result = {1'b0, sum_stage4};
endmodule
